  await seedFakeRegistry(stores.registry);

  app.get("/health", async () => ({ ok: true }));
  registerRunRoutes(app, {
    ...stores,
    eventBus,
    launcher,
    runService
  });
  registerRegistryRoutes(app, { registry: stores.registry });

  return app;
}

